<template><SiteLayout><section class="mx-auto max-w-3xl px-4 py-14"><h1 class="text-4xl font-black">Verify Certificate</h1><form class="mt-8 rounded border bg-white p-6" @submit.prevent="submit"><input v-model="code" class="field" placeholder="YCKF-CERT-DEMO-001"><button class="rounded bg-emerald-700 px-5 py-3 font-bold text-white">Verify</button></form><div v-if="result" class="mt-5 rounded border p-5" :class="result.valid?'bg-emerald-50':'bg-red-50'"><p class="font-black">{{ result.valid?'Certificate is valid':'Certificate not found' }}</p><p v-if="result.valid" class="mt-2">Student: {{ result.student?.name || result.student?.email }}<br>Course: {{ result.course?.title }}</p></div></section></SiteLayout></template>
<script setup lang="ts">import { onMounted,ref } from 'vue';import { useRoute } from 'vue-router';import SiteLayout from '../components/SiteLayout.vue';import { verifyCertificate } from '../services/courseService';const route=useRoute();const code=ref('YCKF-CERT-DEMO-001');const result=ref<any>(null);async function submit(){result.value=await verifyCertificate(code.value)}onMounted(()=>{if(typeof route.query.code==='string'){code.value=route.query.code;submit()}});</script><style scoped>.field{margin-bottom:1rem;width:100%;border:1px solid #cbd5e1;border-radius:.375rem;padding:.85rem}</style>
